// // This module implements a three-input OR gate followed by an inverter and a buffer. The module outputs X, which is the complement of the logical OR of inputs A1, A2, and B1.
module top_module(
    X,
    A1,
    A2,
    B1
);// Module ports
    output X;
    input A1;
    input A2;
    input B1;

    // Module supplies
    supply1 VPWR;
    supply0 VGND;

    // Local signals
    wire and_out;
    wire inv_out;

    // AND gate
    and and1 (and_out, A1, A2, B1);

    // Inverter
    not inv1 (inv_out, and_out);

    // Buffer
    buf buf1 (X, inv_out);

endmodule
